#include "seek.h"
void expand_path(char* p){if(p[0]=='~'){char t[MAX_PATH];snprintf(t,MAX_PATH,"%s%s",home_dir,p+1);strncpy(p,t,MAX_PATH);}else if(strcmp(p,"-")==0)strncpy(p,previous_dir,MAX_PATH);}
void print_match(const char* p,struct stat* s){printf("%s%s%s\n",S_ISDIR(s->st_mode)?"\033[1;34m":"\033[1;32m",p,"\033[0m");}
void handle_file(const char* p){FILE*f=fopen(p,"r");if(!f)return;int c;while((c=fgetc(f))!=EOF)putchar(c);fclose(f);}
void seek_in_directory(const char*s,const char*d,int fd,int ff,int fe){int f=0;if(fd&&ff){fprintf(stderr,"Invalid flags!\n");return;}search_directory(d,s,fd,ff,fe,&f);if(!f)printf("No match found!\n");}
void search_directory(const char*dir,const char*s,int fd,int ff,int fe,int*f){DIR*d=opendir(dir);if(!d)return;struct dirent*e;struct stat st;char fp[MAX_PATH];int mc=0;char mp[MAX_PATH];int isd=0;while((e=readdir(d))!=NULL){snprintf(fp,MAX_PATH,"%s/%s",dir,e->d_name);if(stat(fp,&st)==-1)continue;int id=S_ISDIR(st.st_mode);if((fd&&!id)||(ff&&id))continue;if(strcmp(e->d_name,s)==0){print_match(fp,&st);*f=1;mc++;if(mc==1){strncpy(mp,fp,MAX_PATH);isd=id;}}if(id&&strcmp(e->d_name,".")&&strcmp(e->d_name,".."))search_directory(fp,s,fd,ff,fe,f);}closedir(d);if(fe&&mc==1){if(isd){if(access(mp,X_OK)==0){if(chdir(mp)==0)printf("New folder!\n");}else printf("Missing permissions!\n");}else{if(access(mp,R_OK)==0)handle_file(mp);else printf("Missing permissions!\n");}}}
